import React, { useState, useEffect } from 'react';

const Dashboard = ({ token }) => {
    const [stats, setStats] = useState({ total: 0, applied: 0, interview: 0, offered: 0 });
    const [recentApps, setRecentApps] = useState([]);
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        fetchData();
    }, []);

    const fetchData = async () => {
        try{
            const statsRes = await fetch('/api/applications/stats', {
                headers: { 'Authorization': token }
            });
            const statsData = await statsRes.json();
            setStats(statsData);

            const appsRes = await fetch('/api/applications', {
                headers: { 'Authorization': token }
            });
            const appsData = await appsRes.json();
            setRecentApps(appsData.slice(0, 5));
        }catch(err){
            console.error('Error fetching data');
        }finally{
            setLoading(false);
        }
    };

    if(loading){
        return <div style={{ textAlign: 'center', padding: '50px' }}>Loading...</div>;
    }

    return(
        <div>
            <h1 style={{ marginBottom: '20px' }}>Dashboard</h1>
            
            <div className="stats">
                <div className="stat-box">
                    <div className="stat-number">{stats.total}</div>
                    <div>Total Apps</div>
                </div>
                <div className="stat-box">
                    <div className="stat-number">{stats.applied}</div>
                    <div>Applied</div>
                </div>
                <div className="stat-box">
                    <div className="stat-number">{stats.interview}</div>
                    <div>Interview</div>
                </div>
                <div className="stat-box">
                    <div className="stat-number">{stats.offered}</div>
                    <div>Offers</div>
                </div>
            </div>

            <div className="card">
                <h2>Recent Applications</h2>
                {recentApps.length === 0 ? (
                    <p>No applications yet. Add your first application!</p>
                ) : (
                    <table>
                        <thead>
                            <tr><th>Company</th><th>Position</th><th>Status</th><th>Date</th></tr>
                        </thead>
                        <tbody>
                            {recentApps.map(app => (
                                <tr key={app._id}>
                                    <td>{app.company}</td>
                                    <td>{app.position}</td>
                                    <td><span className={`status status-${app.status}`}>{app.status}</span></td>
                                    <td>{new Date(app.date).toLocaleDateString()}</td>
                                </tr>
                            ))}
                        </tbody>
                    </table>
                )}
            </div>
        </div>
    );
};

export default Dashboard;
